/* ================================================
   FEL TO PRINT — app.js
   ================================================ */


const FEL_LOGO = 'data:image/png;base64,';

const MARCA = 'data:image/png;base64,';

/* ── ESTADO ── */
const state = {
  xmlData:   null,
  logoData:  null,
  logoAlign: 'left',
  size:      'media',
  colors: {
    header:'#1a1a2e', headerText:'#ffffff',
    bg:'#ffffff', tableHeader:'#1a1a2e',
    accent:'#0055a5', text:'#111827'
  },
  font:      "'Inter', sans-serif",
  toggles: {
    nit_emisor:true, dir_emisor:true, correo_emisor:false,
    dir_receptor:true, autorizacion:true, certificador:true, qr:true
  },
  footerText:'¡Gracias por su compra!'
};

/* ── XML PARSER ── */
function parseXML(xml) {
  const doc = new DOMParser().parseFromString(xml,'application/xml');
  const NS  = 'http://www.sat.gob.gt/dte/fel/0.2.0';
  const $   = t => { const e=doc.getElementsByTagNameNS(NS,t); return e.length?e[0]:null; };
  const at  = (el,a) => el?(el.getAttribute(a)||''):'';
  const tx  = (el,t) => { const e=el?el.getElementsByTagNameNS(NS,t):[]; return e.length?e[0].textContent.trim():''; };

  const dg=$('DatosGenerales'),em=$('Emisor'),re=$('Receptor');
  const cert=$('Certificacion'),na=$('NumeroAutorizacion');
  const dEm=$('DireccionEmisor'),dRe=$('DireccionReceptor');

  let esFPEQ = at(dg,'Tipo')==='FPEQ';
  for (const f of doc.getElementsByTagNameNS(NS,'Frase'))
    if (f.getAttribute('TipoFrase')==='3') esFPEQ=true;

  const items=[];
  for (const it of doc.getElementsByTagNameNS(NS,'Item')) {
    const g=t=>tx(it,t);
    items.push({ cantidad:g('Cantidad'), descripcion:g('Descripcion'),
      precioUnitario:+g('PrecioUnitario')||0, descuento:+g('Descuento')||0, total:+g('Total')||0 });
  }

  const totEl=$('Totales');
  const granTotal=totEl?+(totEl.getElementsByTagNameNS(NS,'GranTotal')[0]?.textContent||0):0;

  const fechaISO=at(dg,'FechaHoraEmision');
  let fecha=fechaISO;
  try { fecha=new Date(fechaISO).toLocaleDateString('es-GT',{day:'2-digit',month:'2-digit',year:'numeric'}); } catch(e){}

  const uuid=na?na.textContent.trim():'';
  const nitEm=at(em,'NITEmisor');
  const nitRe=at(re,'IDReceptor');
  const qrUrl=`https://felpub.c.sat.gob.gt/verificador-web/publico/vistas/verificacionDte.jsf`
             +`?tipo=autorizacion&numero=${uuid}&emisor=${nitEm}&receptor=${nitRe}&monto=${granTotal.toFixed(2)}`;

  return {
    tipo:at(dg,'Tipo'), esFPEQ,
    emisor:{ nit:nitEm, nombreComercial:at(em,'NombreComercial'), nombre:at(em,'NombreEmisor'),
             correo:at(em,'CorreoEmisor'),
             direccion:dEm?tx(dEm,'Direccion'):'', municipio:dEm?tx(dEm,'Municipio'):'', departamento:dEm?tx(dEm,'Departamento'):'' },
    receptor:{ nit:nitRe, nombre:at(re,'NombreReceptor'), correo:at(re,'CorreoReceptor'),
               direccion:dRe?tx(dRe,'Direccion'):'' },
    cert:{ nit:cert?tx(cert,'NITCertificador'):'', nombre:cert?tx(cert,'NombreCertificador'):'',
           uuid, serie:na?at(na,'Serie'):'', numero:na?at(na,'Numero'):'' },
    fecha, items, granTotal, qrUrl
  };
}

/* ── UTILIDADES ── */
const fmtQ = v => 'Q '+parseFloat(v).toFixed(2).replace(/\B(?=(\d{3})+(?!\d))/g,',');

function numLetras(n) {
  const U=['','UNO','DOS','TRES','CUATRO','CINCO','SEIS','SIETE','OCHO','NUEVE'];
  const T=['DIEZ','ONCE','DOCE','TRECE','CATORCE','QUINCE','DIECISÉIS','DIECISIETE','DIECIOCHO','DIECINUEVE'];
  const D=['','','VEINTE','TREINTA','CUARENTA','CINCUENTA','SESENTA','SETENTA','OCHENTA','NOVENTA'];
  const C=['','CIEN','DOSCIENTOS','TRESCIENTOS','CUATROCIENTOS','QUINIENTOS','SEISCIENTOS','SETECIENTOS','OCHOCIENTOS','NOVECIENTOS'];
  if(!n)return'CERO'; let r='';
  if(n>=1000){const m=Math.floor(n/1000);r+=(m===1?'MIL':numLetras(m)+' MIL');n%=1000;if(n)r+=' ';}
  if(n>=100){const c=Math.floor(n/100);r+=(n===100?'CIEN':C[c]);n%=100;if(n)r+=' ';}
  if(n>=20){const d=Math.floor(n/10),u=n%10;r+=D[d]+(u?' Y '+U[u]:'');}
  else if(n>=10)r+=T[n-10]; else if(n>0)r+=U[n];
  return r.trim();
}
const fmtLetras = v => { const e=Math.floor(v),c=Math.round((v-e)*100); return numLetras(e)+' QUETZALES'+(c?' CON '+c+'/100':''); };

function buildQR(container, url, size) {
  container.innerHTML='';
  if (!url) return;
  if (typeof QRCode!=='undefined') {
    new QRCode(container,{text:url,width:size,height:size,correctLevel:QRCode.CorrectLevel.M});
  } else {
    const img=document.createElement('img');
    img.src=`https://api.qrserver.com/v1/create-qr-code/?size=${size}x${size}&data=${encodeURIComponent(url)}`;
    img.alt='QR SAT'; img.style.cssText=`width:${size}px;height:${size}px;display:block;`;
    container.appendChild(img);
  }
}

/* ═══════════════════════════════════════════════
   RENDER TICKET
   Sin colores de encabezado, logo centrado,
   orden: emisor → doc → sep → comprador → fecha
          → items → totales → frase → auth → QR
═══════════════════════════════════════════════ */
function renderTicket(inv, d) {
  inv.className = 'invoice size-ticket';
  inv.style.background = '#fff';
  inv.style.color = '#000';
  inv.style.fontFamily = state.font;

  const logo = state.logoData
    ? `<div class="tk-logo"><img src="${state.logoData}" alt="Logo"></div>` : '';

  const emisorNombre = d.emisor.nombreComercial || d.emisor.nombre;
  let emisorLines = `<div class="tk-nombre">${emisorNombre}</div>`;
  if (d.emisor.nombreComercial && d.emisor.nombre !== d.emisor.nombreComercial)
    emisorLines += `<div class="tk-line">${d.emisor.nombre}</div>`;
  if (state.toggles.nit_emisor)
    emisorLines += `<div class="tk-line">${d.emisor.nit}</div>`;
  if (state.toggles.dir_emisor && d.emisor.direccion)
    emisorLines += `<div class="tk-line">${d.emisor.direccion}${d.emisor.municipio?', '+d.emisor.municipio:''}${d.emisor.departamento?', '+d.emisor.departamento:''}</div>`;
  if (state.toggles.correo_emisor && d.emisor.correo)
    emisorLines += `<div class="tk-line">${d.emisor.correo}</div>`;

  const tipoLabel = d.tipo==='FPEQ' ? 'Factura Pequeño Contribuyente' : 'Factura Electrónica';

  // Tabla items
  const isCarta = false; // ticket nunca muestra descuento
  const itemRows = d.items.map(i=>`<tr>
    <td class="tc-c w-qty">${i.cantidad}</td>
    <td>${i.descripcion}</td>
    <td class="tc-r tc-n w-total">${fmtQ(i.total)}</td>
  </tr>`).join('');

  // Frase fiscal
  const fraseHtml = d.esFPEQ
    ? `<div class="tk-phrase">No genera derecho a crédito fiscal.</div>` : '';

  // Auth
  let authHtml = '';
  if (state.toggles.autorizacion && d.cert.uuid)
    authHtml += `<div class="tk-info"><span class="tk-uuid">Autorización: ${d.cert.uuid}</span></div>`;
  if (state.toggles.certificador && d.cert.nombre)
    authHtml += `<div class="tk-info">${d.cert.nombre} NIT: ${d.cert.nit}</div>`;

  // Pie de página
  const footerHtml = state.footerText.trim()
    ? `<div class="tk-info" style="margin-top:6px">${state.footerText}</div>` : '';

  // QR
  const qrHtml = state.toggles.qr && d.qrUrl
    ? `<div class="tk-qr" id="tk-qr-el"></div>` : '';

  // Comprador
  let compradorHtml = `<div class="tk-comprador">
    <div><span class="tk-clabel">NIT: </span><span class="tk-cval">${d.receptor.nit}</span></div>
    <div><span class="tk-clabel">NOMBRE: </span><span class="tk-cval">${d.receptor.nombre}</span></div>`;
  if (state.toggles.dir_receptor && d.receptor.direccion)
    compradorHtml += `<div><span class="tk-clabel">DIRECCIÓN: </span><span class="tk-cval">${d.receptor.direccion}</span></div>`;
  compradorHtml += `</div>`;

  inv.innerHTML = `
    ${logo}
    <div class="tk-emisor">${emisorLines}</div>

    <div class="tk-doc">
      <div class="tk-tipo">${tipoLabel}</div>
      <div class="tk-num">No. ${d.cert.numero}   Serie: ${d.cert.serie}</div>
    </div>

    <div class="tk-sep">-------DATOS DEL COMPRADOR-------</div>
    ${compradorHtml}
    <div class="tk-fecha">FECHA: ${d.fecha}</div>

    <hr class="tk-hr">

    <table class="tk-table">
      <thead><tr>
        <th class="tc-c w-qty">Cant</th>
        <th>Descripción</th>
        <th class="tc-r w-total">Total</th>
      </tr></thead>
      <tbody>${itemRows}</tbody>
    </table>

    <div class="tk-totals">
      <div class="tk-grand-row"><span>TOTAL</span><span>${fmtQ(d.granTotal)}</span></div>
      <div class="tk-words">${fmtLetras(d.granTotal)}</div>
    </div>

    <hr class="tk-hr">

    ${fraseHtml}
    ${authHtml}
    ${footerHtml}
    ${qrHtml}
  `;

  // Renderizar QR después de insertar el DOM
  if (state.toggles.qr && d.qrUrl) {
    const qrEl = inv.querySelector('#tk-qr-el');
    if (qrEl) setTimeout(()=>buildQR(qrEl, d.qrUrl, 80), 50);
  }
}

/* ═══════════════════════════════════════════════
   RENDER MEDIA CARTA / CARTA
   Layout:
   ┌──────────────────────────────────────────┐
   │ [LOGO?]  NOMBRE EMISOR (banner color)   │ [DOC BLOCK 25%]
   │          datos emisor centrado          │
   │                              [FECHA]    │
   ├────────────────────┬────────────────────┤
   │ RECEPTOR (2/3)     │                    │
   ├────────────────────┴────────────────────┤
   │ TABLA DE ITEMS                          │
   │ TOTALES                                 │
   │ [spacer]                                │
   │ [QR]  [frase + auth]                    │
   │ FOOTER                                  │
   │                              [FEL LOGO] │
   └──────────────────────────────────────────┘
═══════════════════════════════════════════════ */
function renderMediaCarta(inv, d) {
  const s = state.size;
  inv.className = `invoice size-${s}`;
  inv.style.background = state.colors.bg;
  inv.style.color      = state.colors.text;
  inv.style.fontFamily = state.font;

  const hc = state.colors.header;
  const ht = state.colors.headerText;
  const ac = state.colors.accent;
  const th = state.colors.tableHeader;

  // Logo HTML
  const logoImg = state.logoData
    ? `<img src="${state.logoData}" alt="Logo">` : '';

  // Construir datos emisor
  let emisorData = '';
  if (state.toggles.nit_emisor)
    emisorData += `<div>NIT: ${d.emisor.nit}</div>`;
  if (state.toggles.dir_emisor && d.emisor.direccion)
    emisorData += `<div>${[d.emisor.direccion,d.emisor.municipio,d.emisor.departamento].filter(Boolean).join(', ')}</div>`;
  if (state.toggles.correo_emisor && d.emisor.correo)
    emisorData += `<div>${d.emisor.correo}</div>`;
  if (d.emisor.nombreComercial && d.emisor.nombre !== d.emisor.nombreComercial)
    emisorData = `<div>${d.emisor.nombre}</div>` + emisorData;

  const tipoLabel = d.tipo==='FPEQ' ? 'Factura Pequeño Contribuyente' : 'Factura Electrónica';

  // ── BLOQUE DOCUMENTO: position:absolute, esquina superior
  //    right:0 por defecto; left:0 si logo está a la derecha
  const docSide    = state.logoAlign === 'right' ? 'left:0' : 'right:0';
  const headerClass = state.logoAlign === 'right' ? 'mc-header doc-left' : 'mc-header';
  const docBlock = `<div class="mc-doc-block" style="${docSide}">
    <span class="mc-doc-badge" style="background:${hc};color:${ht}">${tipoLabel}</span>
    <div class="mc-doc-num">No. ${d.cert.numero}</div>
    <div class="mc-doc-num">Serie: ${d.cert.serie}</div>
  </div>`;

  // ── LOGO según alineación ──
  // Izquierda/derecha: float dentro del header (clearfix activo)
  // Centro: bloque encima del nombre dentro del bloque emisor
  const logoFloatLeft  = state.logoData && state.logoAlign === 'left'
    ? `<div class="mc-logo-float mc-logo-left">${logoImg}</div>` : '';
  const logoFloatRight = state.logoData && state.logoAlign === 'right'
    ? `<div class="mc-logo-float mc-logo-right">${logoImg}</div>` : '';
  const logoCenterHtml = state.logoData && state.logoAlign === 'center'
    ? `<div class="mc-logo-center">${logoImg}</div>` : '';

  // ── BLOQUE EMISOR CENTRAL ──
  // Nombre: chip inline-block (solo ancho del texto), centrado
  // Datos:  texto centrado debajo, tamaño normal de factura
  const emisorPart = `<div class="mc-emisor-block">
    ${logoCenterHtml}
    <div class="mc-nombre-chip" style="background:${hc};color:${ht}">${d.emisor.nombreComercial || d.emisor.nombre}</div>
    <div class="mc-emisor-data" style="color:${state.colors.text}">${emisorData}</div>
  </div>`;

  // ── HEADER COMPLETO ──
  const headerContent = `${logoFloatLeft}${logoFloatRight}${emisorPart}${docBlock}`;

  // Receptor (2/3 del ancho)
  let receptorInner = `<div class="mc-r-row">
    <span class="mc-r-lbl">NOMBRE:</span>
    <span class="mc-r-name">${d.receptor.nombre}</span>
    <span class="mc-r-nit">NIT: ${d.receptor.nit}</span>
  </div>`;
  if (state.toggles.dir_receptor && d.receptor.direccion)
    receptorInner += `<div class="mc-r-addr"><span class="mc-r-lbl">DIRECCIÓN:</span> ${d.receptor.direccion}</div>`;

  // Tabla
  const isCarta = s === 'carta';
  const thStyle = `style="background:${th};color:#fff"`;
  const tableHeader = isCarta
    ? `<tr ${thStyle}><th class="tc-c w-qty">CANTIDAD</th><th>DESCRIPCIÓN</th><th class="tc-r w-price">P. UNITARIO</th><th class="tc-r w-qty">DESC.</th><th class="tc-r w-total">TOTAL</th></tr>`
    : `<tr ${thStyle}><th class="tc-c w-qty">CANTIDAD</th><th>DESCRIPCIÓN</th><th class="tc-r w-price">P. UNITARIO</th><th class="tc-r w-total">TOTAL</th></tr>`;
  const tableBody = d.items.map(i => isCarta
    ? `<tr><td class="tc-c">${i.cantidad}</td><td>${i.descripcion}</td><td class="tc-r tc-n">${fmtQ(i.precioUnitario)}</td><td class="tc-r tc-n">${fmtQ(i.descuento)}</td><td class="tc-r tc-n">${fmtQ(i.total)}</td></tr>`
    : `<tr><td class="tc-c">${i.cantidad}</td><td>${i.descripcion}</td><td class="tc-r tc-n">${fmtQ(i.precioUnitario)}</td><td class="tc-r tc-n">${fmtQ(i.total)}</td></tr>`
  ).join('');

  // Totales
  const totalesHtml = `<div id="mc-totals">
    <div class="t-grand" style="background:${ac};color:#fff">
      <span>TOTAL</span><span class="t-grand-val">${fmtQ(d.granTotal)}</span>
    </div>
    <div class="t-words">${fmtLetras(d.granTotal)}</div>
  </div>`;

  // Frase fiscal
  const fraseHtml = d.esFPEQ
    ? `<div class="mc-phrase">No genera derecho a crédito fiscal.</div>` : '';

  // Auth
  let authLines = '';
  if (state.toggles.autorizacion && d.cert.uuid)
    authLines += `<div>Autorización: <span class="auth-uuid">${d.cert.uuid}</span></div>`;
  if (state.toggles.certificador && d.cert.nombre)
    authLines += `<div>${d.cert.nombre} Nit: ${d.cert.nit}</div>`;

  // QR
  const qrHtml = state.toggles.qr && d.qrUrl
    ? `<div id="mc-qr"></div>` : '<div></div>';

  // Footer
  const footerHtml = state.footerText.trim()
    ? `<div class="mc-footer">${state.footerText}</div>` : '';

  // FEL Logo
  const felHtml = `<div class="mc-fel"><img src="${FEL_LOGO}" alt="FEL"></div>`;

  inv.innerHTML = `<div class="inv-inner">
    <!-- HEADER -->
    <div class="${headerClass}">${headerContent}</div>

    <!-- FECHA -->
    <div class="mc-fecha-row">
      <div class="mc-fecha-badge" style="background:${hc};color:${ht}">FECHA: ${d.fecha}</div>
    </div>

    <!-- RECEPTOR -->
    <div class="mc-receptor-wrap">
      <span class="mc-r-label">Datos del Comprador</span>
      ${receptorInner}
    </div>

    <!-- TABLA -->
    <table class="mc-table">
      <thead>${tableHeader}</thead>
      <tbody>${tableBody}</tbody>
    </table>

    <!-- TOTALES -->
    <div class="mc-totals-wrap">${totalesHtml}</div>

    <!-- SPACER -->
    <div class="inv-spacer"></div>

    <!-- BOTTOM -->
    <div class="mc-bottom">
      ${qrHtml}
      <div class="mc-bottom-right">
        ${fraseHtml}
        <div class="mc-auth">${authLines}</div>
      </div>
    </div>

    ${footerHtml}
    ${felHtml}
  </div>`;

  // QR render
  if (state.toggles.qr && d.qrUrl) {
    const qrEl = inv.querySelector('#mc-qr');
    if (qrEl) setTimeout(()=>buildQR(qrEl, d.qrUrl, 96), 50);
  }
}

/* ── RENDER PRINCIPAL ── */
function render() {
  if (!state.xmlData) return;
  const inv = document.getElementById('invoiceEl');
  if (state.size === 'ticket') renderTicket(inv, state.xmlData);
  else                         renderMediaCarta(inv, state.xmlData);
}

/* ── PANEL SYSTEM ── */
const panels = {
  xml: {
    title:'Cargar XML de la SAT',
    html:()=>`<div class="p-sec">
      <span class="p-lbl">Archivo XML</span>
      <label class="upload-zone ${state.xmlData?'ok':''}" id="pXmlZone">
        <input type="file" id="pXmlInput" accept=".xml" hidden>
        <svg width="28" height="28" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="17 8 12 3 7 8"/><line x1="12" y1="3" x2="12" y2="15"/></svg>
        <span class="uz-main">${state.xmlData?'✓ XML cargado':'Arrastra el XML aquí'}</span>
        <span class="uz-sub">${state.xmlData?(state.xmlData.cert.numero||''):'o haz clic para explorar'}</span>
      </label>
      <p class="p-hint">Carga el archivo XML de la SAT para visualizar tu factura.</p>
    </div>`,
    init:()=>{
      const z=document.getElementById('pXmlZone'), i=document.getElementById('pXmlInput');
      z.addEventListener('click',()=>i.click());
      z.addEventListener('dragover',e=>{e.preventDefault();z.style.borderColor='#0ea5e9';});
      z.addEventListener('dragleave',()=>z.style.borderColor='');
      z.addEventListener('drop',e=>{e.preventDefault();z.style.borderColor='';loadXML(e.dataTransfer.files[0]);});
      i.addEventListener('change',e=>loadXML(e.target.files[0]));
    }
  },

  logo:{
    title:'Logo del Emisor',
    html:()=>`<div class="p-sec">
      <span class="p-lbl">Imagen del logo</span>
      ${state.logoData
        ?`<div class="logo-box"><img src="${state.logoData}" alt="Logo"><button class="rm-btn" id="pLogoRm">✕</button></div>`
        :`<label class="upload-zone" id="pLogoZone">
            <input type="file" id="pLogoInput" accept="image/*" hidden>
            <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5"><rect x="3" y="3" width="18" height="18" rx="2"/><circle cx="8.5" cy="8.5" r="1.5"/><polyline points="21 15 16 10 5 21"/></svg>
            <span class="uz-main">Subir logo (PNG / JPG)</span>
            <span class="uz-sub">Recomendado: fondo transparente</span>
          </label>`
      }
    </div>
    <div class="p-sec">
      <span class="p-lbl">Alineación (media carta y carta)</span>
      <div class="seg-row">
        <button class="seg-btn ${state.logoAlign==='left'?'on':''}"   data-al="left">← Izquierda</button>
        <button class="seg-btn ${state.logoAlign==='center'?'on':''}" data-al="center">Centro</button>
        <button class="seg-btn ${state.logoAlign==='right'?'on':''}"  data-al="right">Derecha →</button>
      </div>
      <p class="p-hint">En formato Ticket el logo siempre se centra automáticamente.</p>
    </div>`,
    init:()=>{
      document.querySelectorAll('.seg-btn').forEach(b=>b.addEventListener('click',()=>{
        document.querySelectorAll('.seg-btn').forEach(x=>x.classList.remove('on'));
        b.classList.add('on'); state.logoAlign=b.dataset.al; if(state.xmlData)render();
      }));
      const rm=document.getElementById('pLogoRm');
      if(rm) rm.addEventListener('click',()=>{state.logoData=null;if(state.xmlData)render();openPanel('logo');});
      const lz=document.getElementById('pLogoZone'),li=document.getElementById('pLogoInput');
      if(lz&&li){
        lz.addEventListener('click',()=>li.click());
        li.addEventListener('change',e=>{
          const f=e.target.files[0];if(!f)return;
          const r=new FileReader();
          r.onload=ev=>{state.logoData=ev.target.result;if(state.xmlData)render();openPanel('logo');};
          r.readAsDataURL(f);
        });
      }
    }
  },

  personalizar:{
    title:'Personalización',
    html:()=>`<div class="p-sec">
      <span class="p-lbl">Colores</span>
      <div class="color-grid">
        <div class="color-row"><label>Encabezado</label><input type="color" id="cH"  value="${state.colors.header}"></div>
        <div class="color-row"><label>Texto encab.</label><input type="color" id="cHT" value="${state.colors.headerText}"></div>
        <div class="color-row"><label>Fondo factura</label><input type="color" id="cB"  value="${state.colors.bg}"></div>
        <div class="color-row"><label>Cab. tabla</label><input type="color" id="cT"  value="${state.colors.tableHeader}"></div>
        <div class="color-row"><label>Total / Acento</label><input type="color" id="cA"  value="${state.colors.accent}"></div>
        <div class="color-row"><label>Texto general</label><input type="color" id="cTx" value="${state.colors.text}"></div>
      </div>
      <p class="p-hint">Los colores de encabezado no se aplican en el formato Ticket.</p>
    </div>
    <div class="p-sec">
      <span class="p-lbl">Tipografía</span>
      <select class="s-select" id="pFont">
        <option value="'Inter', sans-serif"        ${state.font.includes('Inter')?'selected':''}>Inter — Moderna</option>
        <option value="'Georgia', serif"            ${state.font.includes('Georgia')?'selected':''}>Georgia — Clásica</option>
        <option value="'IBM Plex Mono', monospace"  ${state.font.includes('IBM')?'selected':''}>IBM Plex Mono — Técnica</option>
        <option value="'Arial', sans-serif"         ${state.font.includes('Arial')?'selected':''}>Arial — Simple</option>
        <option value="'Courier New', monospace"    ${state.font.includes('Courier')?'selected':''}>Courier New — Ticket</option>
      </select>
    </div>`,
    init:()=>{
      const map={cH:'header',cHT:'headerText',cB:'bg',cT:'tableHeader',cA:'accent',cTx:'text'};
      Object.entries(map).forEach(([id,k])=>{
        const el=document.getElementById(id);
        if(el) el.addEventListener('input',e=>{state.colors[k]=e.target.value;if(state.xmlData)render();});
      });
      const fs=document.getElementById('pFont');
      if(fs) fs.addEventListener('change',e=>{state.font=e.target.value;if(state.xmlData)render();});
    }
  },

  footer:{
    title:'Pie de Página',
    html:()=>`<div class="p-sec">
      <span class="p-lbl">Texto del pie de página</span>
      <input type="text" class="s-input" id="pFooter" placeholder="Ej: ¡Gracias por su compra!" value="${state.footerText}">
      <p class="p-hint">Aparece al final de la factura en todos los formatos.</p>
    </div>`,
    init:()=>{
      const el=document.getElementById('pFooter');
      if(el) el.addEventListener('input',e=>{state.footerText=e.target.value;if(state.xmlData)render();});
    }
  },

  campos:{
    title:'Campos Visibles',
    html:()=>`<div class="p-sec">
      <span class="p-lbl">Mostrar / Ocultar</span>
      <div class="tog-list">
        ${[['nit_emisor','NIT Emisor'],['dir_emisor','Dirección Emisor'],['correo_emisor','Correo Emisor'],
           ['dir_receptor','Dirección Receptor'],['autorizacion','Código de Autorización'],
           ['certificador','Datos Certificador (SAT)'],['qr','Código QR verificación SAT']
          ].map(([k,l])=>`<label class="tog-row">
            <input type="checkbox" data-k="${k}" ${state.toggles[k]?'checked':''}>
            <span class="tog-track"></span><span>${l}</span>
          </label>`).join('')}
      </div>
    </div>`,
    init:()=>{
      document.querySelectorAll('.tog-row input').forEach(el=>
        el.addEventListener('change',e=>{state.toggles[e.target.dataset.k]=e.target.checked;if(state.xmlData)render();}));
    }
  }
};

let activePanel=null;
window.openPanel=function(name){
  const cfg=panels[name]; if(!cfg)return;
  if(activePanel===name){closePanel();return;}
  activePanel=name;
  document.getElementById('panelTitle').textContent=cfg.title;
  document.getElementById('panelBody').innerHTML=cfg.html();
  document.getElementById('sidePanel').classList.add('open');
  document.getElementById('panelOverlay').classList.add('open');
  document.querySelectorAll('.nav-item').forEach(b=>b.classList.remove('active'));
  const btn=document.getElementById('btn-'+name);
  if(btn)btn.classList.add('active');
  if(cfg.init)cfg.init();
};
window.closePanel=function(){
  activePanel=null;
  document.getElementById('sidePanel').classList.remove('open');
  document.getElementById('panelOverlay').classList.remove('open');
  document.querySelectorAll('.nav-item').forEach(b=>b.classList.remove('active'));
};

/* ── XML LOAD ── */
function loadXML(file){
  if(!file)return;
  const r=new FileReader();
  r.onload=e=>{
    try{
      state.xmlData=parseXML(e.target.result);
      document.getElementById('emptyState').style.display='none';
      document.getElementById('invoiceWrap').style.display='';
      document.getElementById('btn-imprimir').disabled=false;
      document.getElementById('btn-pdf').disabled=false;
      closePanel();
      setTimeout(render,80);
    }catch(err){alert('Error al leer el XML: '+err.message);console.error(err);}
  };
  r.readAsText(file,'UTF-8');
}

/* ── PRINT ── */
window.doPrint=()=>{if(state.xmlData)window.print();};

/* ── PDF ── */
window.doPDF=()=>{
  if(!state.xmlData)return;
  if(typeof html2pdf==='undefined'){
    loadScript('https://cdnjs.cloudflare.com/ajax/libs/html2pdf.js/0.10.1/html2pdf.bundle.min.js',()=>setTimeout(genPDF,200));
    return;
  }
  genPDF();
};

function genPDF(){
  const inv=document.getElementById('invoiceEl');
  const sizes={ticket:[80,200],media:[139.7,215.9],carta:[215.9,279.4]};
  const fmt=sizes[state.size]||sizes.media;
  const opt={
    margin:0,
    filename:`factura_${state.xmlData.cert.numero||'FEL'}.pdf`,
    image:{type:'jpeg',quality:.99},
    html2canvas:{scale:3,useCORS:true,allowTaint:true,backgroundColor:'#ffffff',width:inv.offsetWidth,height:inv.offsetHeight},
    jsPDF:{unit:'mm',format:fmt,orientation:'portrait'}
  };
  const bs=inv.style.boxShadow,bb=inv.style.border;
  inv.style.boxShadow='none'; inv.style.border='none';
  html2pdf().set(opt).from(inv).save().then(()=>{inv.style.boxShadow=bs;inv.style.border=bb;});
}

function loadScript(src,cb){
  if(document.querySelector(`script[src="${src}"]`)){if(cb)cb();return;}
  const s=document.createElement('script');s.src=src;s.onload=cb||null;document.head.appendChild(s);
}

/* ── INIT ── */
document.addEventListener('DOMContentLoaded',()=>{
  loadScript('https://cdnjs.cloudflare.com/ajax/libs/qrcodejs/1.0.0/qrcode.min.js');
  loadScript('https://cdnjs.cloudflare.com/ajax/libs/html2pdf.js/0.10.1/html2pdf.bundle.min.js');

  const si=document.getElementById('marcaLogoSidebar');
  if(si){si.src=MARCA;si.style.display='block';}

  document.getElementById('xmlInputHidden')?.addEventListener('change',e=>loadXML(e.target.files[0]));

  document.querySelectorAll('.fmt-tab').forEach(btn=>btn.addEventListener('click',()=>{
    document.querySelectorAll('.fmt-tab').forEach(b=>b.classList.remove('active'));
    btn.classList.add('active');
    state.size=btn.dataset.size;
    if(state.xmlData)render();
  }));
});
